import React, { useState, useEffect } from 'react';
import { PageId, NavItem } from '../types';

interface NavbarProps {
  currentPage: PageId;
  onNavigate: (page: PageId) => void;
}

const Navbar: React.FC<NavbarProps> = ({ currentPage, onNavigate }) => {
  const [scrolled, setScrolled] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleNavClick = (id: PageId) => {
    onNavigate(id);
    setIsMenuOpen(false);
  };

  const navItems: NavItem[] = [
    { label: 'Services', id: 'services' },
    { label: 'How we work', id: 'how-we-work' },
    { label: 'Product', id: 'product' },
    { label: 'About Us', id: 'about-us' },
  ];

  return (
    <>
      <nav className={`fixed top-0 w-full z-[60] transition-all duration-300 ${
        scrolled ? 'bg-white/90 backdrop-blur-xl shadow-lg py-3 border-b border-slate-100' : 'bg-transparent py-5'
      }`}>
        <div className="max-w-[1440px] mx-auto px-4 sm:px-6 lg:px-10">
          <div className="flex justify-between items-center h-14">
            <button 
              onClick={() => handleNavClick('home')}
              className="flex items-center gap-2 group focus:outline-none"
            >
              <div className="w-10 h-10 bg-primary rounded-lg flex items-center justify-center text-white shadow-lg shadow-primary/20 transition-transform group-hover:scale-105">
                <span className="material-icons-round">bolt</span>
              </div>
              <span className="font-display font-extrabold text-2xl tracking-tight text-slate-900">StellarSpark</span>
            </button>

            {/* Desktop Navigation */}
            <div className="hidden md:flex items-center space-x-8">
              {navItems.map((item) => (
                <button 
                  key={item.id} 
                  onClick={() => handleNavClick(item.id)}
                  className={`font-semibold transition hover:text-primary focus:outline-none text-xs uppercase tracking-widest ${
                    currentPage === item.id 
                      ? 'text-primary' 
                      : 'text-slate-500'
                  }`}
                >
                  {item.label}
                </button>
              ))}
            </div>

            <div className="hidden md:flex items-center">
              <button 
                onClick={() => handleNavClick('contact')}
                className="bg-primary hover:bg-secondary text-white px-8 py-2.5 rounded-full font-semibold shadow-lg shadow-primary/30 transition-all transform hover:-translate-y-0.5"
              >
                Talk to Us
              </button>
            </div>

            {/* Mobile Menu Toggle */}
            <div className="md:hidden">
              <button 
                onClick={() => setIsMenuOpen(!isMenuOpen)}
                className="focus:outline-none p-2 text-slate-900"
                aria-label="Toggle menu"
              >
                <span className="material-icons-round text-3xl">
                  {isMenuOpen ? 'close' : 'menu'}
                </span>
              </button>
            </div>
          </div>
        </div>
      </nav>

      {/* Mobile Navigation Menu Overlay */}
      <div 
        className={`fixed inset-0 z-50 bg-white transition-transform duration-300 md:hidden ${
          isMenuOpen ? 'translate-y-0' : '-translate-y-full'
        }`}
      >
        <div className="flex flex-col h-full pt-28 px-6 pb-10">
          <div className="space-y-6 flex-grow">
            {navItems.map((item) => (
              <button
                key={item.id}
                onClick={() => handleNavClick(item.id)}
