const ParticleWave: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;
    let width = canvas.width = canvas.parentElement?.clientWidth || window.innerWidth;
    let height = canvas.height = canvas.parentElement?.clientHeight || 600;

    const particles: { x: number; z: number; baseOpacity: number }[] = [];
    const countX = 60;
    const countZ = 40;

    const initParticles = () => {
      particles.length = 0;
      const spacingX = width / countX;
      const spacingZ = height / countZ;
      for (let x = 0; x < countX; x++) {
        for (let z = 0; z < countZ; z++) {
          particles.push({
            x: x * spacingX,
            z: z * spacingZ,
            baseOpacity: 0.8 + Math.random() * 0.5
          });
        }
      }
    };

    initParticles();

    let time = 0;
    const render = () => {
      time += 0.01;
      ctx.clearRect(0, 0, width, height);

      const centerX = width / 2;
      const centerY = height / 2;

      particles.forEach((p) => {
        const dx = p.x - centerX;
        const dz = p.z - centerY;
        const dist = Math.sqrt(dx * dx + dz * dz);

        const wave = Math.sin(dist * 0.01 - time * 2) * 25;
        const y = centerY + wave + (dz * 0.3);

        const scale = (p.z / height) * 0.6 + 0.4;
        const size = 1.8 * scale;

        const edgeFade = Math.min(1, (width - Math.abs(dx * 2)) / (width * 0.3)) * 
                         Math.min(1, (height - Math.abs(dz * 2)) / (height * 0.3));

        const opacity = p.baseOpacity * scale * edgeFade * (0.4 + Math.sin(time + dist * 0.02) * 0.3);

        if (opacity > 0.01) {
          ctx.beginPath();
          ctx.arc(p.x, y, size, 0, Math.PI * 2);
          ctx.fillStyle = `rgba(96, 122, 251, ${opacity * 0.3})`;
          ctx.fill();
        }
      });

      animationFrameId = requestAnimationFrame(render);
    };

    const handleResize = () => {
      if (!canvas.parentElement) return;
      width = canvas.width = canvas.parentElement.clientWidth;
      height = canvas.height = canvas.parentElement.clientHeight;
      initParticles();
    };

    window.addEventListener('resize', handleResize);
    render();

    return () => {
      cancelAnimationFrame(animationFrameId);
      window.removeEventListener('resize', handleResize);
    };
  }, []);

  return (
    <canvas 
      ref={canvasRef} 
      className="absolute inset-0 z-0 pointer-events-none opacity-90"
    />
  );
};

