      </h3>

      {!result ? (
        <form onSubmit={handleSubmit} className="space-y-4">
          <textarea
            value={problem}
            onChange={(e) => setProblem(e.target.value)}
            placeholder="Describe a business challenge you're facing..."
            className="w-full bg-slate-50 border border-slate-200 rounded-xl p-4 text-sm text-slate-900 placeholder-slate-400 focus:ring-primary focus:border-primary"
            rows={3}
          />
          <button
            type="submit"
            disabled={loading}
            className="w-full bg-primary hover:bg-secondary text-white font-bold py-3 rounded-xl transition-all flex items-center justify-center gap-2 shadow-lg shadow-primary/20"
          >
            {loading ? (
              <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
            ) : (
              'Get AI Analysis'
            )}
          </button>
        </form>
      ) : (
        <div className="space-y-4 animate-in fade-in duration-500">
          <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
            <p className="text-slate-600 text-sm italic mb-2">"{problem}"</p>
