            <div className="bg-slate-50 p-3 rounded-lg border border-slate-100">
              <span className="text-xs text-slate-400 block mb-1 font-bold">Next Steps</span>
              <ul className="text-[10px] text-slate-700 space-y-1 font-semibold">
                {result.nextSteps.map((s, i) => <li key={i}>• {s}</li>)}
