import React, { useState, useEffect } from 'react';
import { PageId, NavItem } from '../types';

interface NavbarProps {
  currentPage: PageId;
  onNavigate: (page: PageId) => void;
}

const Navbar: React.FC<NavbarProps> = ({ currentPage, onNavigate }) => {
  const [scrolled, setScrolled] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleNavClick = (id: PageId) => {
    onNavigate(id);
    setIsMenuOpen(false);
  };

  const navItems: NavItem[] = [
    { label: 'Protocols', id: 'services' },
    { label: 'Process', id: 'how-we-work' },
    { label: 'Systems', id: 'product' },
    { label: 'Core', id: 'about-us' },
  ];

  return (
    <>
      <nav className={`fixed top-4 left-1/2 -translate-x-1/2 w-[95%] max-w-[1400px] z-[60] transition-all duration-500 ${
        scrolled ? 'top-2' : 'top-6'
      }`}>
        <div className={`glass rounded-2xl px-6 h-16 flex items-center justify-between border-white/10 shadow-2xl ${
          scrolled ? 'bg-darkblue/80 scale-x-[0.98]' : 'bg-transparent'
        }`}>
          <button 
            onClick={() => handleNavClick('home')}
            className="flex items-center gap-3 group focus:outline-none"
          >
            <div className="w-9 h-9 bg-primary/20 rounded-lg flex items-center justify-center text-accent border border-accent/30 shadow-[0_0_15px_rgba(34,211,238,0.2)] group-hover:scale-110 transition-transform">
              <span className="material-icons-round text-xl">blur_on</span>
            </div>
            <span className="font-display font-extrabold text-xl tracking-tighter text-white">STELLAR<span className="text-accent">SPARK</span></span>
          </button>

          {/* Desktop HUD Nav */}
          <div className="hidden md:flex items-center space-x-1">
            {navItems.map((item) => (
              <button 
                key={item.id} 
                onClick={() => handleNavClick(item.id)}
                className={`px-4 py-2 rounded-lg text-xs font-bold tracking-widest uppercase transition-all hover:bg-white/5 ${
                  currentPage === item.id ? 'text-accent bg-white/10' : 'text-slate-400'
                }`}
              >
                {item.label}
              </button>
            ))}
          </div>

          <div className="hidden md:flex items-center">
            <button 
              onClick={() => handleNavClick('contact')}
              className="bg-white/10 hover:bg-primary text-white text-xs font-bold uppercase tracking-widest px-6 py-2.5 rounded-lg border border-white/20 transition-all active:scale-95"
            >
              Contact Terminal
            </button>
          </div>

          <div className="md:hidden flex items-center">
            <button onClick={() => setIsMenuOpen(!isMenuOpen)} className="text-white p-2">
              <span className="material-icons-round">{isMenuOpen ? 'close' : 'menu'}</span>
            </button>
          </div>
        </div>
      </nav>

      {/* Mobile Glass Menu */}
      <div 
        className={`fixed inset-0 z-[55] glass transition-all duration-500 md:hidden ${
          isMenuOpen ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'
        }`}
      >
        <div className="flex flex-col items-center justify-center h-full space-y-8">
          {navItems.map((item) => (
            <button
              key={item.id}
              onClick={() => handleNavClick(item.id)}
              className={`text-4xl font-display font-extrabold tracking-tighter ${
                currentPage === item.id ? 'text-accent' : 'text-white'
              }`}
            >
              {item.label}
            </button>
          ))}
          <button 
            onClick={() => handleNavClick('contact')}
            className="bg-primary text-white px-10 py-4 rounded-xl font-bold uppercase tracking-widest"
          >
            Start Project
          </button>
        </div>
      </div>
    </>
  );
};

export default Navbar;

