import React, { useState } from 'react';
import { getProjectConsultation } from '../services/geminiService';
import { ConsultationResponse } from '../types';

const ConsultationWidget: React.FC = () => {
  const [problem, setProblem] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<ConsultationResponse | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!problem.trim()) return;

    setLoading(true);
    const consultation = await getProjectConsultation(problem);
    setResult(consultation);
    setLoading(false);
  };

  return (
    <div className="glass rounded-[2rem] p-8 border-white/10 shadow-[0_20px_50px_rgba(0,0,0,0.5)] relative overflow-hidden group">
      <div className="absolute top-0 right-0 w-32 h-32 bg-primary/10 blur-[40px] rounded-full translate-x-1/2 -translate-y-1/2"></div>

      <div className="flex items-center justify-between mb-8">
        <h3 className="text-white text-sm font-bold tracking-[0.2em] uppercase flex items-center gap-3">
          <span className="w-2 h-2 bg-accent rounded-full animate-pulse shadow-[0_0_10px_#22d3ee]"></span>
          AI Consultant v3.1
        </h3>
        <div className="flex gap-1.5">
          <div className="w-2 h-2 rounded-full bg-white/10"></div>
          <div className="w-2 h-2 rounded-full bg-white/10"></div>
          <div className="w-2 h-2 rounded-full bg-white/10"></div>
        </div>
      </div>

      {!result ? (
        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="relative">
            <textarea
              value={problem}
              onChange={(e) => setProblem(e.target.value)}
              placeholder="System diagnostics: Describe your challenge..."
              className="w-full bg-black/40 border border-white/5 rounded-2xl p-6 text-sm text-white placeholder-slate-600 focus:border-primary focus:ring-4 focus:ring-primary/10 transition-all min-h-[140px] outline-none"
              rows={4}
            />
            <div className="absolute bottom-4 right-4 text-[10px] font-mono text-slate-700">INPUT_BUFFER_ACTIVE</div>
          </div>
          <button
            type="submit"
            disabled={loading}
            className="w-full bg-gradient-to-r from-primary to-secondary hover:brightness-110 text-white font-bold py-4 rounded-xl transition-all flex items-center justify-center gap-3 group/btn disabled:opacity-50"
          >
            {loading ? (
              <div className="flex items-center gap-2">
                <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                <span className="text-xs uppercase tracking-widest font-mono">Processing Data...</span>
              </div>
            ) : (
              <>
                <span className="uppercase tracking-[0.2em] text-xs">Execute Analysis</span>
                <span className="material-icons-round text-lg group-hover/btn:translate-x-1 transition-transform">memory</span>
              </>
            )}
          </button>
        </form>
      ) : (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="bg-white/5 p-6 rounded-2xl border border-white/10 space-y-4">
            <div className="flex items-center gap-2 text-[10px] font-bold text-accent tracking-widest uppercase mb-2">
              <span className="material-icons-round text-sm">verified</span>
              Optimization Logic
            </div>
            <p className="text-white text-sm leading-relaxed font-medium">
              {result.recommendation}
            </p>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="glass p-4 rounded-xl border-white/5">
              <span className="text-[10px] text-slate-500 block mb-2 font-bold tracking-widest uppercase">Complexity Score</span>
              <span className="text-white text-xs font-bold font-mono text-accent">{result.estimatedEffort}</span>
            </div>
            <div className="glass p-4 rounded-xl border-white/5">
              <span className="text-[10px] text-slate-500 block mb-2 font-bold tracking-widest uppercase">Phase 01-03</span>
              <ul className="text-[10px] text-slate-300 space-y-2 font-mono">
                {result.nextSteps.map((s, i) => (
                  <li key={i} className="flex gap-2">
                    <span className="text-primary">></span>
                    {s}
                  </li>
                ))}
              </ul>
            </div>
          </div>

          <button 
            onClick={() => {setResult(null); setProblem('');}}
            className="w-full text-slate-500 text-[10px] font-bold uppercase tracking-[0.3em] hover:text-white transition-colors"
          >
            [ Reset Logic Engine ]
          </button>
        </div>
      )}
    </div>
  );
};

export default ConsultationWidget;

