const ParticleWave: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;
    let width = canvas.width = canvas.parentElement?.clientWidth || window.innerWidth;
    let height = canvas.height = canvas.parentElement?.clientHeight || 600;

    const particles: { x: number; z: number; baseOpacity: number }[] = [];
    const countX = 50;
    const countZ = 40;
    const spacingX = width / countX;
    const spacingZ = height / countZ;

    for (let x = 0; x < countX; x++) {
      for (let z = 0; z < countZ; z++) {
        particles.push({
          x: x * spacingX,
          z: z * spacingZ,
          baseOpacity: 0.7 + Math.random() * 0.3
        });
      }
    }

    let time = 0;
    const render = () => {
      time += 0.012;
      ctx.clearRect(0, 0, width, height);

      const centerX = width / 2;
      const centerY = height / 2;

      particles.forEach((p) => {
        const wave1 = Math.sin(p.x * 0.005 + time) * 35;
        const wave2 = Math.sin(p.z * 0.008 + time * 1.2) * 25;
        const y = centerY + wave1 + wave2 + (p.z - height / 2) * 0.5;

        const scale = (p.z / height) * 0.8 + 0.2;
        const size = 1.3 * scale;
        const opacity = p.baseOpacity * scale * (0.5 + Math.sin(time + p.x * 0.01) * 0.5);

        ctx.beginPath();
        ctx.arc(p.x, y, size, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(168, 85, 247, ${opacity * 0.7})`; // Use primary purple
        ctx.fill();
      });

      animationFrameId = requestAnimationFrame(render);
    };

    const handleResize = () => {
      if (!canvas.parentElement) return;
      width = canvas.width = canvas.parentElement.clientWidth;
      height = canvas.height = canvas.parentElement.clientHeight;
    };

    window.addEventListener('resize', handleResize);
    render();

    return () => {
      cancelAnimationFrame(animationFrameId);
      window.removeEventListener('resize', handleResize);
    };
  }, []);

  return (
    <canvas 
      ref={canvasRef} 
      className="absolute inset-0 z-0 pointer-events-none opacity-40"
    />
  );
};

